queries.sparql:
PREFIX : <http://ambrosia.example.org/agriculture#>
PREFIX p: <http://ambrosia.example.org/agriculture/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?ingredient_name WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:hasIngredients ?child ; p:hasPesticides ?parent . } GROUP BY ?child }
  ?child p:name ?ingredient_name .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :Pesticides } }
  FILTER(?nf = ?total)
}

ambiguous_dsl.choice_dsl:
PREFIX : <http://ambrosia.example.org/agriculture#>
PREFIX p: <http://ambrosia.example.org/agriculture/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
CHOICE scope {
  distributive: { SELECT ?name ?ingredient_name WHERE {
  ?pesticides_ingredients a :Pesticides_Ingredients .
  ?ingredients a :Ingredients .
  ?pesticides_ingredients p:hasIngredients ?ingredients .
  ?pesticides a :Pesticides .
  ?pesticides_ingredients p:hasPesticides ?pesticides .
  ?pesticides p:name ?name .
  ?ingredients p:name ?ingredient_name .
} }
  collective: { SELECT ?ingredient_name WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:hasIngredients ?child ; p:hasPesticides ?parent . } GROUP BY ?child }
  ?child p:name ?ingredient_name .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :Pesticides } }
  FILTER(?nf = ?total)
} }
}
